class UWeaponComponent : public UActorComponent
{
    GENERATED_BODY()
public:
    AActor* Target;
    TArray<ABullet*> ActiveBullets;

    void Fire()
    {
        ABullet* Bullet = GetWorld()->SpawnActor<ABullet>(BulletClass);
        Bullet->SetOwner(GetOwner());
        ActiveBullets.Add(Bullet);
    }

    void ClearBullets()
    {
        for (auto* B : ActiveBullets)
        {
            B->Destroy();
        }
    }
};
